      KNOWLEDGE: { base: "2D", skills: { "alien species": "4D+2", streetwise: "5D", survival: "5D+2", "willpower: torture": "8D+2" } },
      MECHANICAL: { base: "2D", skills: { "space transports": "5D+2", "starship gunnery": "5D+2" } },
      PERCEPTION: { base: "3D", skills: { con: "5D", hide: "5D+2", search: "5D+2", sneak: "7D" } },
