      MECHANICAL: { base: "2D", skills: { "ground vehicle operation": "3D" } },
      PERCEPTION: { base: "3D", skills: { gambling: "3D+1", persuasion: "4D" } },
      STRENGTH: { base: "7D", skills: { brawling: "7D+2", lifting: "7D+1", stamina: "7D+2" } },
